sql:
SELECT service_name, executed_by, exec_date, status, MAX(duration) AS longest_duration
FROM service_executions
GROUP BY service_name, executed_by, exec_date, status;

SELECT service_name, status
FROM service_executions
WHERE executed_by = 'Bob Williams';

SELECT SUM(duration) AS total_duration
FROM service_executions
WHERE service_name = 'ComplianceCheck';

SELECT COUNT(*) AS failed_executions_count
FROM service_executions
WHERE status = 'failure';

SELECT service_name, endpoint
FROM service_definitions
WHERE method = 'GET';

external_knowledge:
- 'Service Masters' refers to the top users who have executed the most services with the longest average execution time; 
- 'time at bat' refers to the average execution time of each service; 
- 'mastery' refers to the ranking of users based on their average execution time across all services in descending order.

sql:
SELECT service_name, duration
FROM service_executions
ORDER BY duration DESC;
